import { GoogleGenAI, Type } from "@google/genai";
import { ListingMode, PropertyData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const TERMINOLOGY_GUIDE = `
CRITICAL TERMINOLOGY MAPPING & REAL ESTATE LOGIC:
- 専有面積 -> 專有面積 (室內)
- バルコニー面積 -> 陽台面積
- 管理費 -> 管理費
- 修繕積立金 -> 修繕積立金
- リフォーム / リノベーション -> 室內翻新 / 裝潢
- 引渡時期 -> 引渡 / 入居時間
- 所有権 -> 所有權
- 構造 -> 結構 (如 RC造)
- オートロック -> 智慧門禁 / 自動鎖
- 浴室乾燥機 -> 浴室暖風乾燥機
- システムキッチン -> 系統廚具
- ウォシュレット -> 免治馬桶

RENTAL FEE LOGIC (CRITICAL):
- 賃料 / 家賃 -> Rent (租金)
- 敷金 / 保証金 -> Deposit (押金). Usually in months (e.g., "1ヶ月" = 1個月).
- 礼金 -> Key Money (禮金). Usually in months (e.g., "1ヶ月" = 1個月).
- 單位識別: If the document says "1", "1ヶ月", "1 month", "1個月", extract it exactly as "1個月".
- 日本租房知識: 禮金與押金的「1個月」基準為「家賃(租金)」，不包含「管理費」。
`;

