export const generateListingText = async (
  data: PropertyData,
  mode: ListingMode
): Promise<string> => {
  const modelName = "gemini-2.5-flash";
  const templateToUse = mode === ListingMode.RENTAL ? RENTAL_TEMPLATE : SALE_TEMPLATE;

  const prompt = `
    You are Linus, a Taiwanese Real Estate Agent in Tokyo.
    Task: Fill out the ${mode} template based on the provided JSON data.

    Data: ${JSON.stringify(data)}

    Special Instructions for Rental Template:
    - If keyMoney/deposit is "1個月", keep it as "1個月" in the text.
    - If keyMoney/deposit is "無" or "0", write "0個月" or "免禮押".

    Special Instructions for Sale Template:
    1. **Renovation_Status_Line**: If 'renovationDate' exists, write "▫︎ {renovationDate} 全室室內設備翻新完成". Else, omit.
    2. **Total_Floors_Line**: Use 'totalFloors'.
    3. **Floor_Part**: Mention current floor 'floor'.
    4. **Year_Month**: Use building age/year 'age'.
    5. **Features_List**: List key features (including elevator, security, etc.) using "／" as separator.
    6. **Dynamic Hashtags**: Include area tags like #{Station}生活 #{Area}房產 plus general #日本買房 #東京置產.

    ${TERMINOLOGY_GUIDE}
    Rules: NO Markdown (bold/italics), output plain text only. Professional yet warm tone.

    Template:
    ${templateToUse}
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
    });
    return response.text || "Error generating text.";
  } catch (error) {
    console.error(error);
    return "Generation failed.";
  }
};

export const rewriteListingText = async (
  currentText: string,
  instruction: string
): Promise<string> => {
  const modelName = "gemini-2.5-flash";
  const prompt = `
    You are an expert copywriter. Rewrite this property listing.
    Instruction: ${instruction}
    Text: ${currentText}
    ${TERMINOLOGY_GUIDE}
    Output ONLY the rewritten text. Plain text, no markdown.
  `;
  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
    });
    return response.text || currentText;
  } catch (error) {
    return currentText;
  }
};

export const extractPropertyData = async (
  files: { mimeType: string; data: string }[],
  supplementaryText: string = ""
): Promise<Partial<PropertyData>> => {
  const modelName = "gemini-2.5-flash";

  const prompt = `
    Analyze the documents and supplementary text: "${supplementaryText}"
    Extract property details into JSON format. Translate values to Traditional Chinese.

    IMPORTANT JAPANESE RENTAL LOGIC:
    - Look for '敷金' or '保証金' (Deposit). If it says '1ヶ月', extract '1個月'. 
    - Look for '礼金' (Key Money). If it says '1ヶ月', extract '1個月'.
    - '賃料' is the base rent. '管理費' or '共益費' is the monthly fee.
    - If you find a currency amount (e.g., 150,000円), extract that. If you find a month count (e.g., 1ヶ月), extract that as 'X個月'.

    Fields to find:
    - address (所在地)
    - line (沿線)
    - station (駅名)
    - walkTime (徒歩時間, extract just the number or 'X分')
    - price (価格/賃料 - e.g., 8,350萬 or 15.5萬)
    - keyMoney (礼金 - e.g., '1個月' or '無')
    - deposit (敷金/保証金 - e.g., '1個月' or '2個月')
    - managementFee (管理費/共益費)
    - layout (間取り - e.g., 1LDK)
    - size (専有面積 - e.g., 45.89)
    - balconySize (バルコニー面積)
    - floor (所在階 - e.g., 2階)
    - totalFloors (建物階数 - e.g., 地上7階)
    - age (築年月 - e.g., 2010年10月)
    - repairFund (修繕積立金)
    - moveInDate (引渡/入居時期)
    - renovationDate (翻新日期)
    - features (設備特色 - Concatenate with "／")

    Rules:
    - Be extremely sensitive to 'ヶ月' appearing near '敷金' and '礼金'.
    - If a field is not found, leave as empty string.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          ...files.map(f => ({ inlineData: f })),
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            address: { type: Type.STRING },
            line: { type: Type.STRING },
            station: { type: Type.STRING },
            walkTime: { type: Type.STRING },
            price: { type: Type.STRING },
            keyMoney: { type: Type.STRING },
            deposit: { type: Type.STRING },
            managementFee: { type: Type.STRING },
            layout: { type: Type.STRING },
            size: { type: Type.STRING },
            balconySize: { type: Type.STRING },
            floor: { type: Type.STRING },
            totalFloors: { type: Type.STRING },
            age: { type: Type.STRING },
            repairFund: { type: Type.STRING },
            moveInDate: { type: Type.STRING },
            renovationDate: { type: Type.STRING },
            features: { type: Type.STRING },
          },
        }
      }
    });

    const text = response.text;
    return text ? JSON.parse(text) : {};
  } catch (error) {
    console.error("Extraction error:", error);
    return {};
  }
};

import React, { useState, useEffect } from 'react';
import { 
  ListingMode, 
  PropertyData
} from './types';
import { 
  INITIAL_PROPERTY_DATA
} from './constants';
import { generateListingText, extractPropertyData, rewriteListingText } from './services/geminiService';
import { 
  Building2, 
  Sparkles, 
  Copy, 
  RefreshCcw,
  CheckCircle2,
  Upload,
  Bot,
  FileText,
  ScanSearch,
  Loader2,
  X,
  Plus,
  Wand2,
  Pencil,
  SendHorizontal,
  Undo2,
  Redo2,
  CalendarDays,
  Info,
  MapPin
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

// Type for uploaded file preview
interface UploadedFile {
  id: string;
  file: File;
  previewUrl: string;
  base64: string;
  mimeType: string;
}

const App = () => {
  // --- State ---
  const [mode, setMode] = useState<ListingMode>(ListingMode.RENTAL);
  const [propertyData, setPropertyData] = useState<PropertyData>(INITIAL_PROPERTY_DATA);

  // Smart Import State
  const [uploadedFiles, setUploadedFiles] = useState<UploadedFile[]>([]);
  const [supplementaryText, setSupplementaryText] = useState("");
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Generation State
  const [generatedText, setGeneratedText] = useState<string>("");
  const [isGenerating, setIsGenerating] = useState(false);
  const [copied, setCopied] = useState(false);
  const [isRewriting, setIsRewriting] = useState(false);
  const [customRewritePrompt, setCustomRewritePrompt] = useState("");

  // History State
  const [textHistory, setTextHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // --- Helpers ---
  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const result = reader.result as string;
        const base64 = result.split(',')[1];
        resolve(base64);
      };
      reader.onerror = error => reject(error);
    });
  };

  // --- History Management ---

  const updateCurrentHistory = (text: string) => {
    setGeneratedText(text);
    if (historyIndex >= 0) {
      const newHistory = [...textHistory];
      newHistory[historyIndex] = text;
      setTextHistory(newHistory);
    }
  };

  const pushToHistory = (text: string, reset: boolean = false) => {
    setGeneratedText(text);
    if (reset) {
      setTextHistory([text]);
      setHistoryIndex(0);
    } else {
      const newHistory = textHistory.slice(0, historyIndex + 1);
      newHistory.push(text);
      setTextHistory(newHistory);
      setHistoryIndex(newHistory.length - 1);
    }
  };

  const handleUndo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setHistoryIndex(newIndex);
      setGeneratedText(textHistory[newIndex]);
    }
  };

  const handleRedo = () => {
    if (historyIndex < textHistory.length - 1) {
      const newIndex = historyIndex + 1;
      setHistoryIndex(newIndex);
      setGeneratedText(textHistory[newIndex]);
    }
  };

  // --- Handlers: Smart Import ---

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0) return;

    const newFiles: UploadedFile[] = [];
    const maxFiles = 5;
    const currentCount = uploadedFiles.length;

    const filesArray = Array.from(e.target.files).slice(0, maxFiles - currentCount) as File[];

    for (const file of filesArray) {
      const base64 = await fileToBase64(file);
      newFiles.push({
        id: Math.random().toString(36).substring(7),
        file,
        previewUrl: URL.createObjectURL(file),
        base64,
        mimeType: file.type
      });
    }

    setUploadedFiles(prev => [...prev, ...newFiles]);
  };

  const removeFile = (id: string) => {
    setUploadedFiles(prev => prev.filter(f => f.id !== id));
  };

  const handleAnalyze = async () => {
    if (uploadedFiles.length === 0 && !supplementaryText) {
      alert("請上傳檔案或輸入文字以進行分析。");
      return;
    }

    setIsAnalyzing(true);
    try {
      const parts = uploadedFiles.map(f => ({
        mimeType: f.mimeType,
        data: f.base64
      }));

      const extractedData = await extractPropertyData(parts, supplementaryText);

      setPropertyData(prev => {
        const next = { ...prev };
        (Object.keys(extractedData) as Array<keyof PropertyData>).forEach(key => {
          if (extractedData[key]) {
            next[key] = extractedData[key]!;
          }
        });
        return next;
      });

    } catch (error) {
      console.error("Analysis failed", error);
      alert("無法分析檔案，請重試。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- Handlers: Generation & Rewrite ---

  const handleGenerateText = async () => {
    setIsGenerating(true);
    const text = await generateListingText(propertyData, mode);
    pushToHistory(text, true);
    setIsGenerating(false);
  };

  const handleRewrite = async (instruction: string) => {
    if (!generatedText || !instruction.trim()) return;
    setIsRewriting(true);
    const newText = await rewriteListingText(generatedText, instruction);
    pushToHistory(newText, false);
    setIsRewriting(false);
    setCustomRewritePrompt("");
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(generatedText);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleInputChange = (field: keyof PropertyData, value: string) => {
    setPropertyData(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-800 font-sans selection:bg-indigo-100 selection:text-indigo-900">
      <header className="sticky top-0 z-50 backdrop-blur-md bg-white/80 border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg text-white">
              <Bot className="w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-900">日本不動產文案生成器</h1>
          </div>
          <div className="flex gap-2 p-1 bg-slate-100 rounded-full border border-slate-200">
            <button 
              onClick={() => { setMode(ListingMode.RENTAL); setPropertyData(INITIAL_PROPERTY_DATA); }}
              className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all ${mode === ListingMode.RENTAL ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              租賃
            </button>
            <button 
              onClick={() => { setMode(ListingMode.SALE); setPropertyData(INITIAL_PROPERTY_DATA); }}
              className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all ${mode === ListingMode.SALE ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              買賣
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-6 grid grid-cols-1 lg:grid-cols-2 gap-6 lg:gap-12">
        <div className="space-y-6">
          <section className="bg-white border border-indigo-100 rounded-2xl p-6 shadow-sm relative overflow-hidden group">
             <div className="absolute top-0 right-0 -mt-4 -mr-4 w-24 h-24 bg-indigo-50 blur-3xl rounded-full transition-transform group-hover:scale-150"></div>
             <h2 className="text-lg font-semibold flex items-center gap-2 mb-2 text-indigo-700">
               <ScanSearch className="w-5 h-5" /> 智慧匯入
             </h2>
             <p className="text-sm text-slate-500 mb-4">第一步：上傳圖紙或照片 (上限5張)，AI將自動提取資訊。</p>
             {uploadedFiles.length > 0 && (
               <div className="mb-4 grid grid-cols-4 sm:grid-cols-5 gap-2">
                 {uploadedFiles.map((file) => (
                   <div key={file.id} className="relative aspect-square rounded-lg overflow-hidden border border-slate-200 group/img">
                     {file.mimeType.startsWith('image/') ? (
                       <img src={file.previewUrl} alt="preview" className="w-full h-full object-cover" />
                     ) : (
                       <div className="w-full h-full flex items-center justify-center bg-slate-50 text-slate-400">
                         <FileText className="w-6 h-6" />
                       </div>
                     )}
                     <button onClick={() => removeFile(file.id)} className="absolute top-0.5 right-0.5 bg-black/50 text-white rounded-full p-0.5 opacity-0 group-hover/img:opacity-100 transition-opacity">
                       <X className="w-3 h-3" />
                     </button>
                   </div>
                 ))}
                 {uploadedFiles.length < 5 && (
                    <label className="flex items-center justify-center aspect-square bg-slate-50 border border-dashed border-slate-300 rounded-lg cursor-pointer hover:bg-slate-100 text-slate-400 transition-colors">
                      <Plus className="w-5 h-5" />
                      <input type="file" className="hidden" multiple accept="image/*,application/pdf" onChange={handleFileSelect} />
                    </label>
                 )}
               </div>
             )}
             {uploadedFiles.length === 0 && (
                <label className="flex flex-col items-center justify-center w-full h-24 border-2 border-dashed border-slate-300 rounded-xl cursor-pointer hover:bg-slate-50 hover:border-indigo-400 transition-colors mb-4">
                    <div className="flex items-center gap-2 text-slate-500">
                      <Upload className="w-5 h-5" />
                      <span className="text-sm font-medium">點擊上傳圖紙/檔案</span>
                    </div>
                    <input type="file" className="hidden" multiple accept="image/*,application/pdf" onChange={handleFileSelect} />
                </label>
             )}
             <div className="mb-4">
               <textarea 
                 placeholder="補充說明 (例如：物件名稱、裝潢細節)..."
                 value={supplementaryText}
                 onChange={(e) => setSupplementaryText(e.target.value)}
                 className="w-full bg-slate-50 border border-slate-200 rounded-lg p-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none resize-none h-20 placeholder:text-slate-400"
               />
             </div>
             <button 
               onClick={handleAnalyze}
               disabled={isAnalyzing || (uploadedFiles.length === 0 && !supplementaryText)}
               className="w-full py-2.5 bg-indigo-600 text-white rounded-lg font-medium text-sm shadow-md hover:bg-indigo-700 active:scale-[0.98] transition-all disabled:opacity-50 flex items-center justify-center gap-2"
             >
               {isAnalyzing ? <><Loader2 className="w-4 h-4 animate-spin" /> 分析中...</> : <><Sparkles className="w-4 h-4" /> 開始 AI 分析</>}
             </button>
          </section>

          <section className="bg-white border border-slate-200 rounded-2xl p-6 shadow-sm">
            <h2 className="text-lg font-semibold flex items-center gap-2 mb-4 text-slate-700">
              <Building2 className="w-5 h-5" /> 物件詳情 - {mode === ListingMode.RENTAL ? '租賃' : '買賣'}
            </h2>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1 col-span-2">
                <label className="text-xs text-slate-500 uppercase font-bold tracking-wider flex items-center gap-1"><MapPin className="w-3 h-3"/> 物件地址</label>
                <input type="text" value={propertyData.address} onChange={(e) => handleInputChange('address', e.target.value)} className="w-full bg-slate-50 border border-slate-300 text-slate-800 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="例：東京都新宿區..." />
              </div>
              <div className="space-y-1">
                <label className="text-xs text-slate-500 uppercase font-bold tracking-wider">路線</label>
                <input type="text" value={propertyData.line} onChange={(e) => handleInputChange('line', e.target.value)} className="w-full bg-slate-50 border border-slate-300 text-slate-800 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none" />
              </div>
              <div className="space-y-1">
                <label className="text-xs text-slate-500 uppercase font-bold tracking-wider">車站名稱</label>
                <input type="text" value={propertyData.station} onChange={(e) => handleInputChange('station', e.target.value)} className="w-full bg-slate-50 border border-slate-300 text-slate-800 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none" />
              </div>
              <div className="space-y-1">
                <label className="text-xs text-slate-500 uppercase font-bold tracking-wider">價格 ({mode === ListingMode.RENTAL ? '租金' : '總價'})</label>
                <input type="text" value={propertyData.price} onChange={(e) => handleInputChange('price', e.target.value)} className="w-full bg-slate-50 border border-slate-300 text-slate-800 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="例：15.5萬" />
              </div>
              <div className="space-y-1">
                <label className="text-xs text-slate-500 uppercase font-bold tracking-wider">徒步時間 (分)</label>
                <input type="text" value={propertyData.walkTime} onChange={(e) => handleInputChange('walkTime', e.target.value)} className="w-full bg-slate-50 border border-slate-300 text-slate-800 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none" />
              </div>

              {mode === ListingMode.RENTAL ? (
                <>
                  <div className="space-y-1">
                    <label className="text-xs text-slate-500 uppercase font-bold tracking-wider text-indigo-600">管理費 / 共益費</label>
                    <input type="text" value={propertyData.managementFee} onChange={(e) => handleInputChange('managementFee', e.target.value)} className="w-full bg-slate-50 border border-indigo-200 text-slate-800 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="例：8000" />
                  </div>
